// middleware.ts
export function middleware(req: NextRequest) {
  const token = req.cookies.get('auth-token');
  if (!token && req.nextUrl.pathname.startsWith('/dashboard')) {
    return NextResponse.redirect(new URL('/login', req.url));
  }
}

// GET /api/projects/:id/stats
export async function getProjectStats(projectId: string) {
  const project = await db.query(
    'SELECT * FROM projects WHERE id = $1',
    [projectId]
  );

  const members = await db.query(
    'SELECT * FROM users WHERE id IN (SELECT user_id FROM project_members WHERE project_id = $1)',
    [projectId]
  );

  const stats = [];
  for (const member of members.rows) {
    const tasks = await db.query(
      'SELECT COUNT(*) FROM tasks WHERE assignee_id = $1 AND project_id = $2',
      [member.id, projectId]
    );
    const completedTasks = await db.query(
      'SELECT COUNT(*) FROM tasks WHERE assignee_id = $1 AND project_id = $2 AND status = $3',
      [member.id, projectId, 'completed']
    );
    stats.push({ member: member.name, total: tasks.rows[0].count, completed: completedTasks.rows[0].count });
  }

  return { project: project.rows[0], memberStats: stats };
}

